    // Expect: x [M,K], w [N,K], b [N]
    const uint64_t x_elems = x_shape->GetOriginShape().GetShapeSize();
    const uint64_t w_elems = w_shape->GetOriginShape().GetShapeSize();
    (void)w_elems;

    // Determine total output length = M * N
    const auto &x_dims = x_shape->GetOriginShape().GetDims();
    const auto &w_dims = w_shape->GetOriginShape().GetDims();
    if (x_dims.size() < 2 || w_dims.size() < 2) {
        return ge::GRAPH_FAILED;
    }
    const uint32_t M = static_cast<uint32_t>(x_dims[x_dims.size()-2]);
    const uint32_t K = static_cast<uint32_t>(x_dims[x_dims.size()-1]);
    const uint32_t N = static_cast<uint32_t>(w_dims[w_dims.size()-2]); // w is [N, K]

    (void)K;

    GemmSigmoidScalingResidualAddCustomTilingData tiling;

    // UB model for epilogue:
    //   inQueue: 2 * tile
    //   outQueue: 2 * tile
    //   tmpQueue: 2 * tile
    // total floats ~ 6 * tile => 24 * tile bytes
    static constexpr uint32_t UB_BYTES = 192 * 1024;
    static constexpr uint32_t ALIGN_ELEMS = 2048;
    uint32_t maxTile = UB_BYTES / 24;
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;

    const uint64_t totalLen64 = static_cast<uint64_t>(M) * static_cast<uint64_t>(N);
    uint32_t totalLen = static_cast<uint32_t>(totalLen64);
    if (totalLen64 > 0xffffffffULL) {
        // large shapes fallback; cap at UINT32_MAX boundary
        totalLen = 0xffffffffu;
    }

    uint32_t tileLen = maxTile;
    if (totalLen < tileLen) {
        const uint32_t aligned = AlignDown(totalLen, ALIGN_ELEMS);
        tileLen = (aligned > 0) ? aligned : totalLen;
    }

    uint32_t numTiles = (tileLen == 0) ? 1u : CeilDiv(totalLen, tileLen);
    uint32_t blockDim = numTiles;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;

    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLen);
    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspaces = context->GetWorkspaceSizes(1);
